import { inject, markRaw, useTemplateRef } from "vue";
import { cloneDeep } from "lodash-es";
import { CopyDocument, Delete, Edit } from "@element-plus/icons-vue";
//#region packages/editor/src/layouts/sidebar/code-block/useContentMenu.ts
var useContentMenu = (deleteCode) => {
	const eventBus = inject("eventBus");
	const menuRef = useTemplateRef("menu");
	let selectId = "";
	const menuData = [
		{
			type: "button",
			text: "编辑",
			icon: Edit,
			display: ({ codeBlockService }) => codeBlockService.getEditStatus(),
			handler: () => {
				if (!selectId) return;
				eventBus?.emit("edit-code", selectId);
			}
		},
		{
			type: "button",
			text: "复制并粘贴至当前",
			icon: markRaw(CopyDocument),
			handler: async ({ codeBlockService }) => {
				if (!selectId) return;
				const codeBlock = codeBlockService.getCodeContentById(selectId);
				if (!codeBlock) return;
				const newCodeId = await codeBlockService.getUniqueId();
				codeBlockService.setCodeDslById(newCodeId, cloneDeep(codeBlock));
			}
		},
		{
			type: "button",
			text: "删除",
			icon: Delete,
			handler: () => {
				if (!selectId) return;
				deleteCode(selectId);
			}
		}
	];
	const nodeContentMenuHandler = (event, data) => {
		event.preventDefault();
		if (data.type === "code") {
			menuRef.value?.show(event);
			if (data.id) selectId = `${data.id}`;
			else selectId = "";
		}
	};
	const contentMenuHideHandler = () => {
		selectId = "";
	};
	return {
		menuData,
		nodeContentMenuHandler,
		contentMenuHideHandler
	};
};
//#endregion
export { useContentMenu };
