const useFormConfig = (props) => {
  const { contentWindow } = props.stage.renderer;
  const mForm = ref();
  const root = ref();
  const values = ref({});
  const curPageId = ref();
  const selectedId = ref();
  const config = computed(
    () => root.value?.items?.find((item) => item.id === curPageId.value) || root.value?.items?.[0]
  );
  const formConfig = computed(() => props.fillConfig(config.value?.items || [], mForm));
  let app = new TMagicApp({
    ua: contentWindow?.navigator.userAgent,
    disabledFlexible: true,
    platform: "editor"
  });
  app.mForm = mForm;
  const resetValues = () => {
    initValue(mForm.value?.formState, {
      initValues: {},
      config: formConfig.value
    }).then((value) => {
      values.value = value;
    });
  };
  const runtimeReadyHandler = ({ data }) => {
    if (!data.tmagicRuntimeReady) {
      return;
    }
    contentWindow?.magic?.onRuntimeReady({
      getApp() {
        return app;
      },
      updateRootConfig(config2) {
        root.value = config2;
        app?.setConfig(config2, curPageId.value);
      },
      updatePageId(id) {
        curPageId.value = id;
        app?.setPage(id);
      },
      select(id) {
        selectedId.value = id;
        if (app?.getPage(id)) {
          this.updatePageId?.(id);
        }
        const el = getElById()(document, `${id}`);
        if (el) return el;
        return nextTick().then(() => getElById()(document, `${id}`));
      },
      add({ config: config2, parentId }) {
        if (!root.value) throw new Error("error");
        if (!selectedId.value) throw new Error("error");
        if (!parentId) throw new Error("error");
        const parent = getNodePath(parentId, [root.value]).pop();
        if (!parent) throw new Error("未找到父节点");
        if (config2.type !== "page") {
          const parentNode = app?.page?.getNode(parent.id);
          parentNode && app?.page?.initNode(config2, parentNode);
        }
        if (parent.id !== selectedId.value) {
          const index = parent.items?.findIndex((child) => child.id === selectedId.value);
          parent.items?.splice(index + 1, 0, config2);
        } else {
          parent.items?.push(config2);
        }
        resetValues();
      },
      update({ config: config2, parentId }) {
        if (!root.value || !app) throw new Error("error");
        const newNode = app.dataSourceManager?.compiledNode(config2) || config2;
        replaceChildNode(reactive(newNode), [root.value], parentId);
        const nodeInstance = app.page?.getNode(config2.id);
        if (nodeInstance) {
          nodeInstance.setData(config2);
        }
        resetValues();
      },
      remove({ id, parentId }) {
        if (!root.value) throw new Error("error");
        const node = getNodePath(id, [root.value]).pop();
        if (!node) throw new Error("未找到目标元素");
        const parent = getNodePath(parentId, [root.value]).pop();
        if (!parent) throw new Error("未找到父元素");
        if (node.type === "page") {
          app?.deletePage();
        } else {
          app?.page?.deleteNode(node.id);
        }
        const index = parent.items?.findIndex((child) => child.id === node.id);
        parent.items.splice(index, 1);
        resetValues();
      }
    });
  };
  contentWindow?.addEventListener("message", runtimeReadyHandler);
  onBeforeUnmount(() => {
    app?.destroy();
    app = void 0;
    contentWindow?.removeEventListener("message", runtimeReadyHandler);
  });
  return {
    mForm,
    config,
    formConfig,
    values
  };
};

