const propsConfigs = configs;
const useRuntime = ({
  plugins = [],
  fillConfig = (config) => config
} = {}) => {
  const render = (stage) => {
    const doc = stage.renderer?.getDocument();
    if (doc) {
      injectStyle(doc, cssStyle);
      injectStyle(
        doc,
        `html,
          body,
          #app {
            width: 100%;
            height: 100%;
            margin: 0;
          }
          ::-webkit-scrollbar {
            width: 0;
          }
        `
      );
    }
    const el = globalThis.document.createElement("div");
    el.id = "app";
    el.style.overflow = "auto";
    const vueApp = createApp(_sfc_main, {
      stage,
      fillConfig
    });
    vueApp.use(formPlugin);
    plugins.forEach((plugin) => vueApp.use(plugin));
    vueApp.mount(el);
    setTimeout(() => {
      uiService.set("showRule", false);
    });
    return el;
  };
  propsService.usePlugin({
    async afterFillConfig(config, itemConfig, labelWidth = "80px") {
      return [
        {
          type: "tab",
          items: [
            {
              title: "属性",
              labelWidth,
              items: [...commonConfig, ...itemConfig]
            }
          ]
        }
      ];
    }
  });
  editorService.usePlugin({
    async afterGetLayout() {
      return Layout.RELATIVE;
    }
  });
  onBeforeUnmount(() => {
    propsService.removeAllPlugins();
    editorService.removeAllPlugins();
  });
  return {
    render
  };
};

