import { getKeys } from "@tmagic/utils";
//#region packages/editor/src/utils/tree.ts
var updateStatus = (nodeStatusMap, id, status) => {
	const nodeStatus = nodeStatusMap.get(id);
	if (!nodeStatus) return;
	getKeys(status).forEach((key) => {
		if (nodeStatus[key] !== void 0 && status[key] !== void 0) nodeStatus[key] = Boolean(status[key]);
	});
};
//#endregion
export { updateStatus };
