import { EventEmitter } from "events";
//#region packages/editor/src/utils/scroll-viewer.ts
var ScrollViewer = class extends EventEmitter {
	container;
	target;
	zoom = 1;
	scrollLeft = 0;
	scrollTop = 0;
	scrollHeight = 0;
	scrollWidth = 0;
	width = 0;
	height = 0;
	translateXCorrectionValue = 0;
	translateYCorrectionValue = 0;
	correctionScrollSize = {
		width: 0,
		height: 0
	};
	resizeObserver = new ResizeObserver(() => {
		this.setSize();
		this.setScrollSize();
	});
	constructor(options) {
		super();
		this.container = options.container;
		this.target = options.target;
		this.zoom = options.zoom;
		if (this.correctionScrollSize) this.correctionScrollSize = {
			...this.correctionScrollSize,
			...options.correctionScrollSize
		};
		this.container.addEventListener("wheel", this.wheelHandler, false);
		this.setSize();
		this.setScrollSize();
		this.resizeObserver.observe(this.container);
		this.resizeObserver.observe(this.target);
	}
	destroy() {
		this.resizeObserver.disconnect();
		this.container.removeEventListener("wheel", this.wheelHandler, false);
		this.removeAllListeners();
	}
	setZoom(zoom) {
		this.zoom = zoom;
		this.setScrollSize();
	}
	scrollTo({ left, top }) {
		if (typeof left !== "undefined") this.scrollLeft = left;
		if (typeof top !== "undefined") this.scrollTop = top;
		const translateX = -this.scrollLeft + this.translateXCorrectionValue;
		const translateY = -this.scrollTop + this.translateYCorrectionValue;
		this.target.style.transform = `translate(${translateX}px, ${translateY}px)`;
	}
	wheelHandler = (event) => {
		const { deltaX, deltaY, currentTarget } = event;
		if (currentTarget !== this.container) return;
		let top;
		if (this.scrollHeight > this.height) top = this.scrollTop + this.getPos(deltaY, this.scrollTop, this.scrollHeight, this.height);
		let left;
		if (this.scrollWidth > this.width) left = this.scrollLeft + this.getPos(deltaX, this.scrollLeft, this.scrollWidth, this.width);
		this.scrollTo({
			left,
			top
		});
		this.emit("scroll", {
			scrollLeft: this.scrollLeft,
			scrollTop: this.scrollTop,
			scrollHeight: this.scrollHeight,
			scrollWidth: this.scrollWidth
		});
	};
	getPos(delta, scrollPos, scrollSize, size) {
		let pos = 0;
		if (delta < 0) {
			if (scrollPos > 0) pos = Math.max(delta, -scrollPos);
		} else {
			const leftPos = scrollSize - size - scrollPos;
			if (leftPos > 0) pos = Math.min(delta, leftPos);
		}
		return pos;
	}
	setScrollSize = () => {
		const targetRect = this.target.getBoundingClientRect();
		this.scrollWidth = targetRect.width * this.zoom + this.correctionScrollSize.width;
		const targetMarginTop = Number(this.target.style.marginTop) || 0;
		this.scrollHeight = (targetRect.height + targetMarginTop) * this.zoom + this.correctionScrollSize.height;
		let left;
		let top;
		if (this.scrollWidth < this.width) {
			left = 0;
			this.translateXCorrectionValue = 0;
		} else this.translateXCorrectionValue = (this.scrollWidth - this.width) / 2;
		if (this.scrollHeight < this.height) {
			top = 0;
			this.translateYCorrectionValue = 0;
		} else this.translateYCorrectionValue = (this.scrollHeight - this.height) / 2;
		this.scrollTo({
			left,
			top
		});
		this.emit("scroll", {
			scrollLeft: this.scrollLeft,
			scrollTop: this.scrollTop,
			scrollHeight: this.scrollHeight,
			scrollWidth: this.scrollWidth
		});
	};
	setSize = () => {
		const { width, height } = this.container.getBoundingClientRect();
		this.width = width;
		this.height = height;
	};
};
//#endregion
export { ScrollViewer };
