//#region packages/editor/src/utils/logger.ts
var log = (...args) => {
	if (process.env.NODE_ENV === "development") console.log("magic editor: ", ...args);
};
var info = (...args) => {
	if (process.env.NODE_ENV === "development") console.info("magic editor: ", ...args);
};
var warn = (...args) => {
	if (process.env.NODE_ENV === "development") console.warn("magic editor: ", ...args);
};
var debug = (...args) => {
	if (process.env.NODE_ENV === "development") console.debug("magic editor: ", ...args);
};
var error = (...args) => {
	if (process.env.NODE_ENV === "development") console.error("magic editor: ", ...args);
};
//#endregion
export { debug, error, info, log, warn };
