import { computed, ref } from "vue";
//#region packages/editor/src/hooks/use-data-source-edit.ts
var useDataSourceEdit = (dataSourceService) => {
	const dialogTitle = ref("");
	const editDialog = ref();
	const dataSourceValues = ref({});
	const editable = computed(() => dataSourceService.get("editable"));
	const editHandler = (id) => {
		if (!editDialog.value) return;
		dataSourceValues.value = { ...dataSourceService.getDataSourceById(id) || {} };
		dialogTitle.value = `编辑${dataSourceValues.value.title || ""}`;
		editDialog.value.show();
	};
	const submitDataSourceHandler = (value, eventData) => {
		if (value.id) dataSourceService.update(value, { changeRecords: eventData.changeRecords });
		else dataSourceService.add(value);
		editDialog.value?.hide();
	};
	return {
		dialogTitle,
		editDialog,
		dataSourceValues,
		editable,
		editHandler,
		submitDataSourceHandler
	};
};
//#endregion
export { useDataSourceEdit };
