		wrapDiv.style.cssText = `
      width: ${sourceEl?.scrollWidth}px;
      height: ${sourceEl?.scrollHeight}px;
      background-color: #fff;
    `;
		for (let i = 0, l = wrapDiv.children.length; i < l; i++) wrapDiv.children[i].remove();
