import { cloneDeep } from "lodash-es";
import { DATA_SOURCE_FIELDS_SELECT_VALUE_PREFIX, NODE_CONDS_KEY, compiledCond, compiledNode, dataSourceTemplateRegExp, getValueByKeyPath, isPage, isPageFragment, replaceChildNode } from "@tmagic/core";
//#region packages/data-source/src/utils.ts
/**
* 编译显示条件
* @param cond 条件配置
* @param data 上下文数据（数据源数据）
* @returns boolean
*/
var compiledCondition = (cond, data) => {
	let result = true;
	for (const { op, value, range, field } of cond) {
		const [sourceId, ...fields] = field;
		const dsData = data[sourceId];
		if (!dsData || !fields.length) break;
		try {
			if (!compiledCond(op, getValueByKeyPath(fields.join("."), dsData), value, range)) {
				result = false;
				break;
			}
		} catch (e) {
			console.warn(e);
		}
	}
	return result;
};
/**
* 编译数据源条件组
* @param node dsl节点
* @param data 数据源数据
* @returns boolean
*/
var compliedConditions = (node, data) => {
	if (!node[NODE_CONDS_KEY] || !Array.isArray(node[NODE_CONDS_KEY]) || !node[NODE_CONDS_KEY].length) return true;
	for (const { cond } of node[NODE_CONDS_KEY]) {
		if (!cond) continue;
		if (compiledCondition(cond, data)) return true;
	}
	return false;
};
var updateNode = (node, dsl) => {
	if (isPage(node) || isPageFragment(node)) {
		const index = dsl.items?.findIndex((child) => child.id === node.id);
		dsl.items.splice(index, 1, node);
	} else replaceChildNode(node, dsl.items);
};
/**
* 创建迭代器容器编译的数据上下文
* @param itemData 迭代数据
* @param dsId 数据源id
* @param fields dsl节点字段，如a.b.c
* @returns 数据上下文
*/
var createIteratorContentData = (itemData, dsId, fields = [], dsData = {}) => {
	const data = {
		...dsData,
		[dsId]: {}
	};
	let rawData = cloneDeep(dsData[dsId]);
	let obj = data[dsId];
	fields.forEach((key, index) => {
		Object.assign(obj, rawData);
		if (index === fields.length - 1) {
			obj[key] = itemData;
			return;
		}
		if (Array.isArray(rawData[key])) {
			rawData[key] = {};
			obj[key] = {};
		}
		rawData = rawData[key];
		obj = obj[key];
	});
	return data;
};
/**
* 编译通过tmagic-editor的数据源源选择器配(data-source-field-select)
* 格式为 [`${DATA_SOURCE_FIELDS_SELECT_VALUE_PREFIX}${id}`, 'field']
* DATA_SOURCE_FIELDS_SELECT_VALUE_PREFIX常量可通过@tmagic/utils获取
*
* @param value dsl节点中的数据源配置
* @param data 数据源数据
* @returns 编译好的配置
*/
var compliedDataSourceField = (value, data) => {
	const [prefixId, ...fields] = value;
	const prefixIndex = prefixId.indexOf(DATA_SOURCE_FIELDS_SELECT_VALUE_PREFIX);
	if (prefixIndex > -1) {
		const dsData = data[prefixId.substring(prefixIndex + DATA_SOURCE_FIELDS_SELECT_VALUE_PREFIX.length)];
		if (!dsData) return value;
		try {
			return getValueByKeyPath(fields.join("."), dsData);
		} catch (e) {
			return value;
		}
	}
	return value;
};
var template = (value, data) => value.replace(dataSourceTemplateRegExp, (match, $1) => {
	try {
		return getValueByKeyPath($1, data);
	} catch (e) {
		return match;
	}
});
/**
* 编译通过tmagic-editor的数据源源选择器（data-source-input，data-source-select，data-source-field-select）配置出来的数据，或者其他符合规范的配置
* @param value dsl节点中的数据源配置
* @param data 数据源数据
* @returns 编译好的配置
*/
var compiledNodeField = (value, data) => {
	if (typeof value === "string") return template(value, data);
	if (value?.isBindDataSource && value.dataSourceId) return data[value.dataSourceId];
	if (value?.isBindDataSourceField && value.dataSourceId && typeof value.template === "string") return template(value.template, data[value.dataSourceId]);
	if (Array.isArray(value) && typeof value[0] === "string") return compliedDataSourceField(value, data);
	return value;
};
var compliedIteratorItem = ({ compile, dsId, item, deps, condDeps, inEditor, ctxData }) => {
	const { items, ...node } = item;
	const newNode = cloneDeep(node);
	if (condDeps[node.id]?.keys.length && !inEditor) newNode.condResult = compliedConditions(node, ctxData);
	if (Array.isArray(items) && items.length) newNode.items = items.map((item) => compliedIteratorItem({
		compile,
		dsId,
		item,
		deps,
		condDeps,
		inEditor,
		ctxData
	}));
	else if (items) newNode.items = items;
	if (!deps[newNode.id]?.keys.length) return newNode;
	return compiledNode(compile, newNode, { [dsId]: deps }, dsId);
};
/**
* 按需加载数据源
*/
var registerDataSourceOnDemand = async (dsl, dataSourceModules) => {
	const { dataSourceMethodsDeps = {}, dataSourceCondDeps = {}, dataSourceDeps = {}, dataSources = [] } = dsl;
	const dsModuleMap = {};
	dataSources.forEach((ds) => {
		let dep = dataSourceCondDeps[ds.id] || {};
		if (!Object.keys(dep).length) dep = dataSourceDeps[ds.id] || {};
		if (!Object.keys(dep).length) dep = dataSourceMethodsDeps[ds.id] || {};
		if (Object.keys(dep).length && dataSourceModules[ds.type]) dsModuleMap[ds.type] = dataSourceModules[ds.type];
	});
	const modules = await Promise.all(Object.values(dsModuleMap).map((asyncModule) => asyncModule()));
	const moduleMap = {};
	modules.forEach((module, index) => {
		const type = Object.keys(dsModuleMap)[index];
		moduleMap[type] = module.default;
	});
	return moduleMap;
};
//#endregion
export { compiledCondition, compiledNodeField, compliedConditions, compliedDataSourceField, compliedIteratorItem, createIteratorContentData, registerDataSourceOnDemand, template, updateNode };
