import { getDataByPage } from "../utils/form.js";
import { computed, ref } from "vue";
//#region packages/form/src/table/usePagination.ts
var usePagination = (props, modelName) => {
	const pageSize = ref(10);
	/**
	* 当前页码
	*/
	const currentPage = ref(0);
	const paginationData = computed(() => getDataByPage(props.model[modelName.value], currentPage.value, pageSize.value));
	const handleSizeChange = (val) => {
		pageSize.value = val;
	};
	const handleCurrentChange = (val) => {
		currentPage.value = val - 1;
	};
	return {
		pageSize,
		currentPage,
		paginationData,
		handleSizeChange,
		handleCurrentChange
	};
};
//#endregion
export { usePagination };
