import base_default from "./formConfigs/base.js";
import http_default from "./formConfigs/http.js";
import { defineFormItem } from "@tmagic/form";
import { dataSourceTemplateRegExp, getKeysArray, isNumber } from "@tmagic/utils";
//#region packages/editor/src/utils/data-source/index.ts
var dataSourceFormConfig = defineFormItem({
	type: "tab",
	items: [
		{
			title: "数据定义",
			items: [{
				name: "fields",
				type: "data-source-fields",
				defaultValue: () => []
			}]
		},
		{
			title: "方法定义",
			items: [{
				name: "methods",
				type: "data-source-methods",
				defaultValue: () => []
			}]
		},
		{
			title: "事件配置",
			items: [{
				name: "events",
				src: "datasource",
				type: "event-select"
			}]
		},
		{
			title: "mock数据",
			items: [{
				name: "mocks",
				type: "data-source-mocks",
				defaultValue: () => []
			}]
		},
		{
			title: "请求参数裁剪",
			display: (_formState, { model }) => model.type === "http",
			items: [{
				name: "beforeRequest",
				type: "vs-code",
				parse: true,
				autosize: {
					minRows: 10,
					maxRows: 30
				}
			}]
		},
		{
			title: "响应数据裁剪",
			display: (_formStat, { model }) => model.type === "http",
			items: [{
				name: "afterResponse",
				type: "vs-code",
				parse: true,
				autosize: {
					minRows: 10,
					maxRows: 30
				}
			}]
		}
	]
});
var fillConfig = (config) => [
	...base_default(),
	...config,
	dataSourceFormConfig
];
var getFormConfig = (type, configs) => {
	switch (type) {
		case "base": return fillConfig([]);
		case "http": return fillConfig(http_default);
		default: return fillConfig(configs[type] || []);
	}
};
var getFormValue = (type, values) => {
	if (type !== "http") return values;
	return {
		beforeRequest: `(options, context) => {
  /**
   * 用户可以直接编写函数，在原始接口调用之前，会运行该函数，将这个函数的返回值作为该数据源接口的入参
   *
   * options: HttpOptions
   *
   * interface HttpOptions {
   *  // 请求链接
   *  url: string;
   *  // query参数
   *  params?: Record<string, string>;
   *  // body数据
   *  data?: Record<string, any>;
   *  // 请求头
   *  headers?: Record<string, string>;
   *  // 请求方法 GET/POST
   *  method?: Method;
   * }
   *
   * context：上下文对象
   *
   * interface Content {
   *  app: TMagicApp;
   *  dataSource: HttpDataSource;
   * }
   *
   * return: HttpOptions
   */

  // 此处的返回值会作为这个接口的入参
  return options;
}`,
		afterResponse: `(response, context) => {
  /**
   * 用户可以直接编写函数，在原始接口返回之后，会运行该函数，将这个函数的返回值作为该数据源接口的返回

    * context：上下文对象
    *
    * interface Content {
    *  app: TMagicApp;
    *  dataSource: HttpDataSource;
    * }
    *
    */

  // 此处的返回值会作为这个接口的返回值
  return response;
}`,
		...values
	};
};
var getDisplayField = (dataSources, key) => {
	const displayState = [];
	const matches = key.matchAll(dataSourceTemplateRegExp);
	let index = 0;
	for (const match of matches) {
		if (typeof match.index === "undefined") break;
		displayState.push({
			type: "text",
			value: key.substring(index, match.index)
		});
		let dsText = "";
		let ds;
		let fields;
		getKeysArray(match[1]).forEach((item, index) => {
			if (index === 0) {
				ds = dataSources.find((ds) => ds.id === item);
				dsText += ds?.title || item;
				fields = ds?.fields;
				return;
			}
			if (isNumber(item)) dsText += `[${item}]`;
			else {
				const field = fields?.find((field) => field.name === item);
				fields = field?.fields;
				dsText += `.${field?.title || item}`;
			}
		});
		displayState.push({
			type: "var",
			value: dsText
		});
		index = match.index + match[0].length;
	}
	if (index < key.length) displayState.push({
		type: "text",
		value: key.substring(index)
	});
	return displayState;
};
var getCascaderOptionsFromFields = (fields = [], dataSourceFieldType = ["any"]) => {
	const typeSet = new Set(dataSourceFieldType.length ? dataSourceFieldType : ["any"]);
	const includesAny = typeSet.has("any");
	const result = [];
	for (const field of fields) {
		const fieldType = field.type || "any";
		const isContainerType = fieldType === "any" || fieldType === "array" || fieldType === "object";
		const children = isContainerType ? getCascaderOptionsFromFields(field.fields, dataSourceFieldType) : [];
		if (includesAny || typeSet.has(fieldType) || isContainerType && children.length) result.push({
			label: `${field.title || field.name}(${field.type})`,
			value: field.name,
			children
		});
	}
	return result;
};
var getFieldType = (ds, fieldNames) => {
	let fields = ds?.fields;
	let type = "";
	for (const fieldName of fieldNames) {
		if (!fields?.length) return "";
		const field = fields.find((f) => f.name === fieldName);
		if (!field) return "";
		type = field.type || "";
		fields = field.fields;
	}
	return type;
};
//#endregion
export { getCascaderOptionsFromFields, getDisplayField, getFieldType, getFormConfig, getFormValue };
