//#region packages/editor/src/utils/monaco-editor.ts
var cached;
var monaco_editor_default = () => {
	if (!cached) cached = Promise.all([import("emmet-monaco-es"), import("monaco-editor")]).then(([emmet, monaco]) => {
		const { emmetHTML, emmetCSS } = emmet;
		emmetHTML(monaco);
		emmetCSS(monaco, ["css", "scss"]);
		return monaco;
	});
	return cached;
};
//#endregion
export { monaco_editor_default as default };
