import { CODE_DRAFT_STORAGE_KEY } from "../type.js";
import BaseService_default from "./BaseService.js";
import { getEditorConfig } from "../utils/config.js";
import storage_default, { Protocol } from "./storage.js";
import { COPY_CODE_STORAGE_KEY } from "../utils/editor.js";
import editor_default from "./editor.js";
import { Target, Watcher } from "@tmagic/core";
import { reactive } from "vue";
import { cloneDeep, get, keys, pick } from "lodash-es";
//#region packages/editor/src/services/codeBlock.ts
var canUsePluginMethods = {
	async: [
		"setCodeDslById",
		"setEditStatus",
		"setCombineIds",
		"setUndeleteableList",
		"deleteCodeDslByIds"
	],
	sync: ["setCodeDslByIdSync"]
};
var CodeBlock = class extends BaseService_default {
	state = reactive({
		codeDsl: null,
		editable: true,
		combineIds: [],
		undeletableList: [],
		paramsColConfig: void 0
	});
	constructor() {
		super([...canUsePluginMethods.async.map((methodName) => ({
			name: methodName,
			isAsync: true
		})), ...canUsePluginMethods.sync.map((methodName) => ({
			name: methodName,
			isAsync: false
		}))]);
	}
	/**
	* 设置活动的代码块dsl数据源
	* @param {CodeBlockDSL} codeDsl 代码DSL
	* @returns {void}
	*/
	async setCodeDsl(codeDsl) {
		this.state.codeDsl = codeDsl;
		this.emit("code-dsl-change", this.state.codeDsl);
	}
	/**
	* 获取活动的代码块dsl数据源（默认从dsl中的codeBlocks字段读取）
	* 方法要支持钩子添加扩展，会被重写为异步方法,因此这里显示写为异步以提醒调用者需以异步形式调用
	* @param {boolean} forceRefresh 是否强制从活动dsl拉取刷新
	* @returns {CodeBlockDSL | null}
	*/
	getCodeDsl() {
		return this.state.codeDsl;
	}
	/**
	* 根据代码块id获取代码块内容
	* @param {Id} id 代码块id
	* @returns {CodeBlockContent | null}
	*/
	getCodeContentById(id) {
		if (!id) return null;
		const totalCodeDsl = this.getCodeDsl();
		if (!totalCodeDsl) return null;
		return totalCodeDsl[id] ?? null;
	}
	/**
	* 设置代码块ID和代码内容到源dsl
	* @param {Id} id 代码块id
	* @param {CodeBlockContent} codeConfig 代码块内容配置信息
	* @returns {void}
	*/
	async setCodeDslById(id, codeConfig) {
		this.setCodeDslByIdSync(id, codeConfig, true);
	}
	/**
	* 为了兼容历史原因
	* 设置代码块ID和代码内容到源dsl
	* @param {Id} id 代码块id
	* @param {CodeBlockContent} codeConfig 代码块内容配置信息
	* @param {boolean} force 是否强制写入，默认true
	* @returns {void}
	*/
	setCodeDslByIdSync(id, codeConfig, force = true) {
		const codeDsl = this.getCodeDsl();
		if (!codeDsl) throw new Error("dsl中没有codeBlocks");
		if (codeDsl[id] && !force) return;
		const codeConfigProcessed = cloneDeep(codeConfig);
		if (codeConfigProcessed.content) {
			const parseDSL = getEditorConfig("parseDSL");
			if (typeof codeConfigProcessed.content === "string") codeConfigProcessed.content = parseDSL(codeConfigProcessed.content);
		}
		codeDsl[id] = {
			...codeDsl[id] || {},
			...codeConfigProcessed
		};
		this.emit("addOrUpdate", id, codeDsl[id]);
	}
	/**
	* 根据代码块id数组获取代码dsl
	* @param {string[]} ids 代码块id数组
	* @returns {CodeBlockDSL}
	*/
	getCodeDslByIds(ids) {
		return pick(this.getCodeDsl(), ids);
	}
	/**
	* 获取编辑状态
	* @returns {boolean} 是否可编辑
	*/
	getEditStatus() {
		return this.state.editable;
	}
	/**
	* 设置编辑状态
	* @param {boolean} status 是否可编辑
	* @returns {void}
	*/
	async setEditStatus(status) {
		this.state.editable = status;
	}
	/**
	* 设置当前选中组件已关联绑定的代码块id数组
	* @param {string[]} ids 代码块id数组
	* @returns {void}
	*/
	async setCombineIds(ids) {
		this.state.combineIds = ids;
	}
	/**
	* 获取当前选中组件已关联绑定的代码块id数组
	* @returns {string[]}
	*/
	getCombineIds() {
		return this.state.combineIds;
	}
	/**
	* 获取不可删除列表
	* @returns {Id[]}
	*/
	getUndeletableList() {
		return this.state.undeletableList;
	}
	/**
	* 设置不可删除列表：为业务逻辑预留的不可删除的代码块列表，由业务逻辑维护（如代码块上线后不可删除）
	* @param {Id[]} codeIds 代码块id数组
	* @returns {void}
	*/
	async setUndeleteableList(codeIds) {
		this.state.undeletableList = codeIds;
	}
	/**
	* 设置代码草稿
	*/
	setCodeDraft(codeId, content) {
		globalThis.localStorage.setItem(`${CODE_DRAFT_STORAGE_KEY}_${codeId}`, content);
	}
	/**
	* 获取代码草稿
	*/
	getCodeDraft(codeId) {
		return globalThis.localStorage.getItem(`${CODE_DRAFT_STORAGE_KEY}_${codeId}`);
	}
	/**
	* 删除代码草稿
	*/
	removeCodeDraft(codeId) {
		globalThis.localStorage.removeItem(`${CODE_DRAFT_STORAGE_KEY}_${codeId}`);
	}
	/**
	* 在dsl数据源中删除指定id的代码块
	* @param {Id[]} codeIds 需要删除的代码块id数组
	*/
	async deleteCodeDslByIds(codeIds) {
		const currentDsl = await this.getCodeDsl();
		if (!currentDsl) return;
		codeIds.forEach((id) => {
			delete currentDsl[id];
			this.emit("remove", id);
		});
	}
	setParamsColConfig(config) {
		this.state.paramsColConfig = config;
	}
	getParamsColConfig() {
		return this.state.paramsColConfig;
	}
	/**
	* 生成代码块唯一id
	* @returns {Id} 代码块唯一id
	*/
	async getUniqueId() {
		const newId = `code_${Math.random().toString(10).substring(2).substring(0, 4)}`;
		if (!keys(await this.getCodeDsl()).includes(newId)) return newId;
		return await this.getUniqueId();
	}
	/**
	* 复制时会带上组件关联的代码块
	* @param config 组件节点配置
	* @returns
	*/
	copyWithRelated(config, collectorOptions) {
		const copyNodes = Array.isArray(config) ? config : [config];
		const copyData = {};
		if (collectorOptions && typeof collectorOptions.isTarget === "function") {
			const customTarget = new Target({ ...collectorOptions });
			const coperWatcher = new Watcher();
			coperWatcher.addTarget(customTarget);
			coperWatcher.collect(copyNodes, {}, true, collectorOptions.type);
			Object.keys(customTarget.deps).forEach((nodeId) => {
				const node = editor_default.getNodeById(nodeId);
				if (!node) return;
				customTarget.deps[nodeId].keys.forEach((key) => {
					const relateCodeId = get(node, key);
					if (!Object.keys(copyData).find((codeId) => codeId === relateCodeId)) {
						const relateCode = this.getCodeContentById(relateCodeId);
						if (relateCode) copyData[relateCodeId] = relateCode;
					}
				});
			});
		}
		storage_default.setItem(COPY_CODE_STORAGE_KEY, copyData, { protocol: Protocol.OBJECT });
	}
	/**
	* 粘贴代码块
	* @returns
	*/
	paste() {
		const codeDsl = storage_default.getItem(COPY_CODE_STORAGE_KEY);
		Object.keys(codeDsl).forEach((codeId) => {
			this.setCodeDslByIdSync(codeId, codeDsl[codeId], false);
		});
	}
	resetState() {
		this.state.codeDsl = null;
		this.state.editable = true;
		this.state.combineIds = [];
		this.state.undeletableList = [];
	}
	destroy() {
		this.resetState();
		this.removeAllListeners();
		this.removeAllPlugins();
	}
	usePlugin(options) {
		super.usePlugin(options);
	}
};
var codeBlock_default = new CodeBlock();
//#endregion
export { codeBlock_default as default };
