import { traverseNode } from "@tmagic/utils";
import { ref, watch } from "vue";
//#region packages/editor/src/hooks/use-node-status.ts
var createPageNodeStatus = (nodeData, initialLayerNodeStatus) => {
	const map = /* @__PURE__ */ new Map();
	nodeData.forEach((node) => traverseNode(node, (node) => {
		map.set(node.id, initialLayerNodeStatus?.get(node.id) || {
			visible: true,
			expand: false,
			selected: false,
			draggable: false
		});
	}));
	return map;
};
var useNodeStatus = (nodeData) => {
	/** 所有页面的节点状态 */
	const nodeStatusMap = ref(/* @__PURE__ */ new Map());
	watch(nodeData, (nodeData) => {
		nodeStatusMap.value = createPageNodeStatus(nodeData, nodeStatusMap.value);
	}, {
		immediate: true,
		deep: true
	});
	return { nodeStatusMap };
};
//#endregion
export { useNodeStatus };
