import props_default from "../services/props.js";
import { generatePageNameByApp, getInitPositionStyle } from "./editor.js";
import editor_default from "../services/editor.js";
import { calcValueByFontsize, getElById, isPage, isPageFragment } from "@tmagic/utils";
import { NodeType } from "@tmagic/core";
import { toRaw } from "vue";
import { isEmpty } from "lodash-es";
//#region packages/editor/src/utils/operator.ts
/**
* 粘贴前置操作：返回分配了新id以及校准了坐标的配置
* @param position 粘贴的坐标
* @param config 待粘贴的元素配置(复制时保存的那份配置)
* @returns
*/
var beforePaste = (position, config, doc) => {
	if (!config[0]?.style) return config;
	const curNode = editor_default.get("node");
	const { left: referenceLeft, top: referenceTop } = config[0].style;
	return config.map((configItem) => {
		const { offsetX = 0, offsetY = 0, ...positionClone } = position;
		let pastePosition = positionClone;
		if (!isEmpty(pastePosition) && curNode?.items) pastePosition = getPositionInContainer(pastePosition, curNode.id, doc);
		if (pastePosition.left && configItem.style?.left) pastePosition.left = configItem.style.left - referenceLeft + pastePosition.left;
		if (pastePosition.top && configItem.style?.top) pastePosition.top = configItem.style?.top - referenceTop + pastePosition.top;
		const pasteConfig = props_default.setNewItemId(configItem, false);
		if (pasteConfig.style) {
			const { left, top } = pasteConfig.style;
			if (typeof left === "number" || !!left && !isNaN(Number(left))) pasteConfig.style.left = Number(left) + offsetX;
			if (typeof top === "number" || !!top && !isNaN(Number(top))) pasteConfig.style.top = Number(top) + offsetY;
			pasteConfig.style = {
				...pasteConfig.style,
				...pastePosition
			};
		}
		const root = editor_default.get("root");
		if ((isPage(pasteConfig) || isPageFragment(pasteConfig)) && root) pasteConfig.name = generatePageNameByApp(root, isPage(pasteConfig) ? NodeType.PAGE : NodeType.PAGE_FRAGMENT);
		return pasteConfig;
	});
};
/**
* 将元素粘贴到容器内时，将相对于画布坐标转换为相对于容器的坐标
* @param position PastePosition 粘贴时相对于画布的坐标
* @param id 元素id
* @returns PastePosition 转换后的坐标
*/
var getPositionInContainer = (position = {}, id, doc) => {
	let { left = 0, top = 0 } = position;
	const stageDoc = editor_default.get("stage")?.renderer?.contentWindow?.document;
	const parentElRect = (stageDoc && getElById()(stageDoc, `${id}`))?.getBoundingClientRect();
	left = left - calcValueByFontsize(doc, parentElRect?.left || 0);
	top = top - calcValueByFontsize(doc, parentElRect?.top || 0);
	return {
		left,
		top
	};
};
var getAddParent = (node) => {
	const curNode = editor_default.get("node");
	let parentNode;
	if (isPage(node)) parentNode = editor_default.get("root");
	else if (curNode?.items) parentNode = curNode;
	else if (curNode?.id) parentNode = editor_default.getParentById(curNode.id, false);
	return parentNode;
};
var getDefaultConfig = async (addNode, parentNode) => {
	const { type, inputEvent, ...config } = addNode;
	const layout = await editor_default.getLayout(toRaw(parentNode), addNode);
	const newNode = { ...toRaw(await props_default.getPropsValue(type, config)) };
	newNode.style = getInitPositionStyle(newNode.style, layout);
	return newNode;
};
//#endregion
export { beforePaste, getAddParent, getDefaultConfig, getPositionInContainer };
