import { UI_SELECT_MODE_EVENT_NAME } from "../../../utils/const.js";
import { updateStatus } from "../../../utils/tree.js";
import { isPage, isPageFragment } from "@tmagic/utils";
import { computed, nextTick } from "vue";
import { throttle } from "lodash-es";
//#region packages/editor/src/layouts/sidebar/layer/use-click.ts
var useClick = ({ editorService, stageOverlayService, uiService }, isCtrlKeyDown, nodeStatusMap, menuRef) => {
	const isMultiSelect = computed(() => isCtrlKeyDown.value && !editorService.get("disabledMultiSelect"));
	const select = async (data) => {
		if (!data.id) throw new Error("没有id");
		if (isMultiSelect.value) multiSelect(data);
		else {
			await editorService.select(data);
			editorService.get("stage")?.select(data.id);
			stageOverlayService.get("stage")?.select(data.id);
		}
	};
	const multiSelect = async (data) => {
		if (isPage(data) || isPageFragment(data)) return;
		const nodes = editorService.get("nodes") || [];
		const newNodes = [];
		let isCancel = false;
		nodes.forEach((node) => {
			if (node.id === data.id) {
				isCancel = true;
				return;
			}
			if (isPage(node) || isPageFragment(node)) return;
			newNodes.push(node.id);
		});
		if (!isCancel || newNodes.length === 0) newNodes.push(data.id);
		await editorService.multiSelect(newNodes);
		editorService.get("stage")?.multiSelect(newNodes);
		stageOverlayService.get("stage")?.multiSelect(newNodes);
	};
	const highlightHandler = throttle((event, data) => {
		highlight(data);
	}, 300);
	const highlight = (data) => {
		editorService.highlight(data);
		editorService.get("stage")?.highlight(data.id);
		stageOverlayService.get("stage")?.highlight(data.id);
	};
	const nodeClickHandler = (event, data) => {
		if (!nodeStatusMap?.value) return;
		if (uiService.get("uiSelectMode")) {
			document.dispatchEvent(new CustomEvent(UI_SELECT_MODE_EVENT_NAME, { detail: data }));
			return;
		}
		if (data.items && data.items.length > 0 && !isMultiSelect.value) updateStatus(nodeStatusMap.value, data.id, { expand: true });
		nextTick(() => {
			select(data);
		});
	};
	return {
		menuRef,
		nodeClickHandler,
		nodeContentMenuHandler(event, data) {
			event.preventDefault();
			const nodes = editorService.get("nodes") || [];
			if (nodes.length < 2 || !nodes.includes(data)) nodeClickHandler(event, data);
			menuRef.value?.show(event);
		},
		highlightHandler
	};
};
//#endregion
export { useClick };
