import BaseService_default from "./BaseService.js";
import storage_default, { Protocol } from "./storage.js";
import { COPY_DS_STORAGE_KEY } from "../utils/editor.js";
import editor_default from "./editor.js";
import { getFormConfig, getFormValue } from "../utils/data-source/index.js";
import { guid, toLine } from "@tmagic/utils";
import { Target, Watcher } from "@tmagic/core";
import { reactive } from "vue";
import { cloneDeep, get } from "lodash-es";
//#region packages/editor/src/services/dataSource.ts
var canUsePluginMethods = {
	async: [],
	sync: [
		"getFormConfig",
		"setFormConfig",
		"getFormValue",
		"setFormValue",
		"getFormEvent",
		"setFormEvent",
		"getFormMethod",
		"setFormMethod",
		"add",
		"update",
		"remove",
		"createId"
	]
};
var DataSource = class extends BaseService_default {
	state = reactive({
		datasourceTypeList: [],
		dataSources: [],
		editable: true,
		configs: {},
		values: {},
		events: {},
		methods: {}
	});
	constructor() {
		super(canUsePluginMethods.sync.map((methodName) => ({
			name: methodName,
			isAsync: false
		})));
	}
	set(name, value) {
		this.state[name] = value;
	}
	get(name) {
		return this.state[name];
	}
	getFormConfig(type = "base") {
		return getFormConfig(toLine(type), this.get("configs"));
	}
	setFormConfig(type, config) {
		this.get("configs")[toLine(type)] = config;
	}
	getFormValue(type = "base") {
		return getFormValue(toLine(type), this.get("values")[type]);
	}
	setFormValue(type, value) {
		this.get("values")[toLine(type)] = value;
	}
	getFormEvent(type = "base") {
		return this.get("events")[toLine(type)] || [];
	}
	setFormEvent(type, value = []) {
		this.get("events")[toLine(type)] = value;
	}
	getFormMethod(type = "base") {
		return this.get("methods")[toLine(type)] || [];
	}
	setFormMethod(type, value = []) {
		this.get("methods")[toLine(type)] = value;
	}
	add(config) {
		const newConfig = {
			...config,
			id: config.id && !this.getDataSourceById(config.id) ? config.id : this.createId()
		};
		this.get("dataSources").push(newConfig);
		this.emit("add", newConfig);
		return newConfig;
	}
	update(config, { changeRecords = [] } = {}) {
		const dataSources = this.get("dataSources");
		const index = dataSources.findIndex((ds) => ds.id === config.id);
		const oldConfig = dataSources[index];
		const newConfig = cloneDeep(config);
		dataSources[index] = newConfig;
		this.emit("update", newConfig, {
			oldConfig,
			changeRecords
		});
		return newConfig;
	}
	remove(id) {
		const dataSources = this.get("dataSources");
		const index = dataSources.findIndex((ds) => ds.id === id);
		dataSources.splice(index, 1);
		this.emit("remove", id);
	}
	createId() {
		return `ds_${guid()}`;
	}
	getDataSourceById(id) {
		return this.get("dataSources").find((ds) => ds.id === id);
	}
	resetState() {
		this.set("dataSources", []);
	}
	destroy() {
		this.removeAllListeners();
		this.resetState();
		this.removeAllPlugins();
	}
	usePlugin(options) {
		super.usePlugin(options);
	}
	/**
	* 复制时会带上组件关联的数据源
	* @param config 组件节点配置
	* @returns
	*/
	copyWithRelated(config, collectorOptions) {
		const copyNodes = Array.isArray(config) ? config : [config];
		const copyData = [];
		if (collectorOptions && typeof collectorOptions.isTarget === "function") {
			const customTarget = new Target({ ...collectorOptions });
			const coperWatcher = new Watcher();
			coperWatcher.addTarget(customTarget);
			coperWatcher.collect(copyNodes, {}, true, collectorOptions.type);
			Object.keys(customTarget.deps).forEach((nodeId) => {
				const node = editor_default.getNodeById(nodeId);
				if (!node) return;
				customTarget.deps[nodeId].keys.forEach((key) => {
					const [relateDsId] = get(node, key);
					if (!copyData.find((dsItem) => dsItem.id === relateDsId)) {
						const relateDs = this.getDataSourceById(relateDsId);
						if (relateDs) copyData.push(relateDs);
					}
				});
			});
		}
		storage_default.setItem(COPY_DS_STORAGE_KEY, copyData, { protocol: Protocol.OBJECT });
	}
	/**
	* 粘贴数据源
	* @returns
	*/
	paste() {
		storage_default.getItem(COPY_DS_STORAGE_KEY).forEach((item) => {
			if (!this.getDataSourceById(item.id)) this.add(item);
		});
	}
};
var dataSource_default = new DataSource();
//#endregion
export { dataSource_default as default };
