import { DepTargetType } from "./types.js";
//#region packages/dep/src/Target.ts
/**
* 需要收集依赖的目标
* 例如：一个代码块可以为一个目标
*/
var Target = class {
	/**
	* 如何识别目标
	*/
	isTarget;
	/**
	* 目标id，不可重复
	* 例如目标是代码块，则为代码块id
	*/
	id;
	/**
	* 目标名称，用于显示在依赖列表中
	*/
	name;
	/**
	* 不同的目标可以进行分类，例如代码块，数据源可以为两个不同的type
	*/
	type = DepTargetType.DEFAULT;
	/**
	* 依赖详情
	* 实例：{ 'node_id': { name: 'node_name', keys: [ created, mounted ] } }
	*/
	deps = {};
	/**
	* 是否默认收集，默认为true，当值为false时需要传入type参数给collect方法才会被收集
	*/
	isCollectByDefault;
	constructor(options) {
		this.isTarget = options.isTarget;
		this.id = options.id;
		this.name = options.name;
		this.isCollectByDefault = options.isCollectByDefault ?? true;
		if (options.type) this.type = options.type;
		if (options.initialDeps) this.deps = options.initialDeps;
	}
	/**
	* 更新依赖
	* @param option 节点配置
	* @param key 哪个key配置了这个目标的id
	*/
	updateDep({ id, name, key, data }) {
		const dep = this.deps[id] || {
			name,
			keys: []
		};
		dep.name = name;
		dep.data = data;
		this.deps[id] = dep;
		if (!dep.keys.includes(key)) dep.keys.push(key);
	}
	/**
	* 删除依赖
	* @param node 哪个节点的依赖需要移除，如果为空，则移除所有依赖
	* @param key 节点下哪个key需要移除，如果为空，则移除改节点下的所有依赖key
	* @returns void
	*/
	removeDep(id, key) {
		if (typeof id === "undefined") {
			Object.keys(this.deps).forEach((depKey) => {
				delete this.deps[depKey];
			});
			return;
		}
		const dep = this.deps[id];
		if (!dep) return;
		if (key) {
			const index = dep.keys.indexOf(key);
			dep.keys.splice(index, 1);
			if (dep.keys.length === 0) delete this.deps[id];
		} else delete this.deps[id];
	}
	/**
	* 判断指定节点下的指定key是否存在在依赖列表中
	* @param node 哪个节点
	* @param key 哪个key
	* @returns boolean
	*/
	hasDep(id, key) {
		return this.deps[id]?.keys.includes(key) ?? false;
	}
	destroy() {
		this.deps = {};
	}
};
//#endregion
export { Target as default };
