import { DSL_NODE_KEY_COPY_PREFIX, Target, Watcher, isDataSourceCondTarget, isDataSourceTarget, traverseNode } from "@tmagic/core";
//#region packages/data-source/src/depsCache.ts
var cache = /* @__PURE__ */ new Map();
var getDeps = (ds, nodes, inEditor) => {
	let cacheKey;
	if (inEditor) {
		const ids = [];
		nodes.forEach((node) => {
			traverseNode(node, (node) => {
				ids.push(node.id);
			});
		});
		cacheKey = `${ds.id}:${ids.join(":")}`;
	} else cacheKey = `${ds.id}:${nodes.map((node) => node.id).join(":")}`;
	if (cache.has(cacheKey)) return cache.get(cacheKey);
	const watcher = new Watcher();
	watcher.addTarget(new Target({
		id: ds.id,
		type: "data-source",
		isTarget: (key, value) => {
			if (`${key}`.includes(DSL_NODE_KEY_COPY_PREFIX)) return false;
			return isDataSourceTarget(ds, key, value, true);
		}
	}));
	watcher.addTarget(new Target({
		id: ds.id,
		type: "cond",
		isTarget: (key, value) => isDataSourceCondTarget(ds, key, value, true)
	}));
	watcher.collect(nodes, {}, true);
	const { deps } = watcher.getTarget(ds.id, "data-source");
	const { deps: condDeps } = watcher.getTarget(ds.id, "cond");
	const result = {
		deps,
		condDeps
	};
	cache.set(cacheKey, result);
	return result;
};
//#endregion
export { getDeps };
