import { inject, markRaw, useTemplateRef } from "vue";
import { cloneDeep } from "lodash-es";
import { CopyDocument, Delete, Edit } from "@element-plus/icons-vue";
//#region packages/editor/src/layouts/sidebar/data-source/useContentMenu.ts
var useContentMenu = () => {
	const eventBus = inject("eventBus");
	const menuRef = useTemplateRef("menu");
	let selectId = "";
	const menuData = [
		{
			type: "button",
			text: "编辑",
			icon: Edit,
			display: ({ dataSourceService }) => dataSourceService.get("editable"),
			handler: () => {
				if (!selectId) return;
				eventBus?.emit("edit-data-source", selectId);
			}
		},
		{
			type: "button",
			text: "复制并粘贴至当前",
			icon: markRaw(CopyDocument),
			handler: ({ dataSourceService }) => {
				if (!selectId) return;
				const ds = dataSourceService.getDataSourceById(selectId);
				if (!ds) return;
				dataSourceService.add(cloneDeep(ds));
			}
		},
		{
			type: "button",
			text: "删除",
			icon: Delete,
			handler: () => {
				if (!selectId) return;
				eventBus?.emit("remove-data-source", selectId);
			}
		}
	];
	const nodeContentMenuHandler = (event, data) => {
		event.preventDefault();
		if (data.type === "ds") {
			menuRef.value?.show(event);
			if (data.id) selectId = `${data.id}`;
			else selectId = "";
		}
	};
	const contentMenuHideHandler = () => {
		selectId = "";
	};
	return {
		menuData,
		nodeContentMenuHandler,
		contentMenuHideHandler
	};
};
//#endregion
export { useContentMenu };
