import { ref } from "vue";
//#region packages/form/src/table/useFullscreen.ts
var useFullscreen = () => {
	const isFullscreen = ref(false);
	const toggleFullscreen = () => {
		if (isFullscreen.value) isFullscreen.value = false;
		else isFullscreen.value = true;
	};
	return {
		isFullscreen,
		toggleFullscreen
	};
};
//#endregion
export { useFullscreen };
