import { buildChangeRecords, getGuideLineFromCache } from "../utils/editor.js";
import editor_default from "../services/editor.js";
import { H_GUIDE_LINE_STORAGE_KEY, UI_SELECT_MODE_EVENT_NAME, V_GUIDE_LINE_STORAGE_KEY } from "../utils/const.js";
import ui_default from "../services/ui.js";
import StageCore, { GuidesType } from "@tmagic/stage";
import { getIdFromEl } from "@tmagic/utils";
import { computed, watch } from "vue";
//#region packages/editor/src/hooks/use-stage.ts
var root = computed(() => editor_default.get("root"));
var page = computed(() => editor_default.get("page"));
var zoom = computed(() => ui_default.get("zoom") || 1);
var uiSelectMode = computed(() => ui_default.get("uiSelectMode"));
var getGuideLineKey = (key) => `${key}_${root.value?.id}_${page.value?.id}`;
var useStage = (stageOptions) => {
	const stage = new StageCore({
		render: stageOptions.render,
		runtimeUrl: stageOptions.runtimeUrl,
		zoom: stageOptions.zoom ?? zoom.value,
		autoScrollIntoView: stageOptions.autoScrollIntoView,
		isContainer: stageOptions.isContainer,
		containerHighlightClassName: stageOptions.containerHighlightClassName,
		containerHighlightDuration: stageOptions.containerHighlightDuration,
		containerHighlightType: stageOptions.containerHighlightType,
		disabledDragStart: stageOptions.disabledDragStart,
		renderType: stageOptions.renderType,
		canSelect: (el, event, stop) => {
			if (!stageOptions.canSelect) return true;
			const elCanSelect = stageOptions.canSelect?.(el);
			if (uiSelectMode.value && elCanSelect && event.type === "mousedown") {
				document.dispatchEvent(new CustomEvent(UI_SELECT_MODE_EVENT_NAME, { detail: el }));
				return stop();
			}
			return elCanSelect;
		},
		moveableOptions: stageOptions.moveableOptions,
		updateDragEl: stageOptions.updateDragEl,
		guidesOptions: stageOptions.guidesOptions,
		disabledMultiSelect: stageOptions.disabledMultiSelect,
		disabledRule: stageOptions.disabledRule
	});
	watch(() => editor_default.get("disabledMultiSelect"), (disabledMultiSelect) => {
		if (disabledMultiSelect) stage.disableMultiSelect();
		else stage.enableMultiSelect();
	});
	stage.mask?.setGuides([getGuideLineFromCache(getGuideLineKey(H_GUIDE_LINE_STORAGE_KEY)), getGuideLineFromCache(getGuideLineKey(V_GUIDE_LINE_STORAGE_KEY))]);
	stage.on("page-el-update", () => {
		editor_default.set("stageLoading", false);
	});
	stage.on("select", (el) => {
		const id = getIdFromEl()(el);
		if (`${editor_default.get("node")?.id}` === id && editor_default.get("nodes").length === 1) return;
		id && editor_default.select(id);
	});
	stage.on("highlight", (el) => {
		const id = getIdFromEl()(el);
		id && editor_default.highlight(id);
	});
	stage.on("multi-select", (els) => {
		const ids = els.map((el) => getIdFromEl()(el)).filter((id) => Boolean(id));
		editor_default.multiSelect(ids);
	});
	stage.on("update", (ev) => {
		if (ev.parentEl) {
			for (const data of ev.data) {
				const id = getIdFromEl()(data.el);
				const pId = getIdFromEl()(ev.parentEl);
				id && pId && editor_default.moveToContainer({
					id,
					style: data.style
				}, pId);
			}
			return;
		}
		ev.data.forEach((data) => {
			const id = getIdFromEl()(data.el);
			if (!id) return;
			const { style = {} } = data;
			editor_default.update({
				id,
				style
			}, { changeRecords: buildChangeRecords(style, "style") });
		});
	});
	stage.on("sort", (ev) => {
		editor_default.sort(ev.src, ev.dist);
	});
	stage.on("remove", (ev) => {
		const nodes = ev.data.map(({ el }) => editor_default.getNodeById(getIdFromEl()(el) || ""));
		editor_default.remove(nodes.filter((node) => Boolean(node)));
	});
	stage.on("select-parent", () => {
		const parent = editor_default.get("parent");
		if (!parent) throw new Error("父节点为空");
		editor_default.select(parent);
		editor_default.get("stage")?.select(parent.id);
	});
	stage.on("change-guides", (e) => {
		ui_default.set("showGuides", true);
		if (!root.value || !page.value) return;
		const storageKey = getGuideLineKey(e.type === GuidesType.HORIZONTAL ? H_GUIDE_LINE_STORAGE_KEY : V_GUIDE_LINE_STORAGE_KEY);
		if (e.guides.length) globalThis.localStorage.setItem(storageKey, JSON.stringify(e.guides));
		else globalThis.localStorage.removeItem(storageKey);
	});
	return stage;
};
//#endregion
export { useStage };
