import { COPY_STORAGE_KEY } from "./editor.js";
import { calcValueByFontsize, isPage, isPageFragment } from "@tmagic/utils";
import { NodeType } from "@tmagic/core";
import { computed, markRaw } from "vue";
import { CopyDocument, Delete, DocumentCopy } from "@element-plus/icons-vue";
//#region packages/editor/src/utils/content-menu.ts
var useDeleteMenu = () => ({
	type: "button",
	text: "删除",
	icon: Delete,
	display: ({ editorService }) => {
		const node = editorService.get("node");
		return node?.type !== NodeType.ROOT && !isPage(node) && !isPageFragment(node);
	},
	handler: ({ editorService }) => {
		const nodes = editorService.get("nodes");
		nodes && editorService.remove(nodes);
	}
});
var useCopyMenu = () => ({
	type: "button",
	text: "复制",
	icon: markRaw(CopyDocument),
	handler: ({ editorService }) => {
		const nodes = editorService?.get("nodes");
		nodes && editorService?.copy(nodes);
	}
});
var usePasteMenu = (menu) => ({
	type: "button",
	text: "粘贴",
	icon: markRaw(DocumentCopy),
	display: ({ storageService }) => !!storageService.getItem(COPY_STORAGE_KEY),
	handler: ({ editorService, uiService }) => {
		const nodes = editorService?.get("nodes");
		if (!nodes || nodes.length === 0) return;
		if (menu?.value?.$el) {
			const stage = editorService.get("stage");
			const rect = menu.value.$el.getBoundingClientRect();
			const parentRect = stage?.container?.getBoundingClientRect();
			const initialLeft = calcValueByFontsize(stage?.renderer?.getDocument(), (rect.left || 0) - (parentRect?.left || 0)) / uiService.get("zoom");
			const initialTop = calcValueByFontsize(stage?.renderer?.getDocument(), (rect.top || 0) - (parentRect?.top || 0)) / uiService.get("zoom");
			editorService.paste({
				left: initialLeft,
				top: initialTop
			});
		} else editorService.paste();
	}
});
var moveTo = (id, { editorService }) => {
	const nodes = editorService.get("nodes") || [];
	const parent = editorService.getNodeById(id);
	if (!parent) return;
	editorService.add(nodes, parent);
	editorService.remove(nodes);
};
var useMoveToMenu = ({ editorService }) => {
	return {
		type: "button",
		text: "移动至",
		display: ({ editorService }) => {
			const node = editorService.get("node");
			const pageLength = editorService.get("pageLength");
			return !isPage(node) && pageLength > 1;
		},
		items: (computed(() => editorService.get("root")).value?.items || []).filter((page) => page.id !== editorService.get("page")?.id).map((page) => ({
			text: `${page.name}(${page.id})`,
			type: "button",
			handler: (services) => {
				moveTo(page.id, services);
			}
		}))
	};
};
//#endregion
export { useCopyMenu, useDeleteMenu, useMoveToMenu, usePasteMenu };
