import { updateStatus } from "../../../utils/tree.js";
import { getNodePath, isPage, isPageFragment, traverseNode } from "@tmagic/utils";
import { computed, onBeforeUnmount, ref, watch } from "vue";
//#region packages/editor/src/layouts/sidebar/layer/use-node-status.ts
var createPageNodeStatus = (page, initialLayerNodeStatus) => {
	const map = /* @__PURE__ */ new Map();
	map.set(page.id, {
		visible: true,
		expand: true,
		selected: true,
		draggable: false
	});
	page.items.forEach((node) => traverseNode(node, (node) => {
		map.set(node.id, initialLayerNodeStatus?.get(node.id) || {
			visible: true,
			expand: false,
			selected: false,
			draggable: true
		});
	}));
	return map;
};
var useNodeStatus = ({ editorService }) => {
	const page = computed(() => editorService.get("page"));
	const nodes = computed(() => editorService.get("nodes"));
	/** 所有页面的节点状态 */
	const nodeStatusMaps = ref(/* @__PURE__ */ new Map());
	/** 当前页面的节点状态 */
	const nodeStatusMap = computed(() => page.value ? nodeStatusMaps.value.get(page.value.id) : /* @__PURE__ */ new Map());
	watch(() => page.value?.id, (pageId) => {
		if (!pageId) return;
		nodeStatusMaps.value.set(pageId, createPageNodeStatus(page.value, nodeStatusMaps.value.get(pageId)));
	}, { immediate: true });
	watch(nodes, (nodes) => {
		if (!nodeStatusMap.value) return;
		for (const [id, status] of nodeStatusMap.value.entries()) {
			status.selected = nodes.some((node) => node.id === id);
			if (status.selected) getNodePath(id, page.value?.items).forEach((node) => {
				updateStatus(nodeStatusMap.value, node.id, { expand: true });
			});
		}
	}, { immediate: true });
	const addHandler = (newNodes) => {
		newNodes.forEach((node) => {
			if (isPage(node) || isPageFragment(node)) return;
			traverseNode(node, (node) => {
				nodeStatusMap.value?.set(node.id, {
					visible: true,
					expand: Array.isArray(node.items),
					selected: true,
					draggable: true
				});
			});
		});
	};
	editorService.on("add", addHandler);
	const removeHandler = (nodes) => {
		nodes.forEach((node) => {
			traverseNode(node, (node) => {
				nodeStatusMap.value?.delete(node.id);
			});
		});
	};
	editorService.on("remove", removeHandler);
	onBeforeUnmount(() => {
		editorService.off("remove", removeHandler);
		editorService.off("add", addHandler);
	});
	return {
		nodeStatusMaps,
		nodeStatusMap
	};
};
//#endregion
export { useNodeStatus };
