import { tMagicMessage } from "@tmagic/design";
import { nextTick, ref, useTemplateRef } from "vue";
import { cloneDeep } from "lodash-es";
//#region packages/editor/src/hooks/use-code-block-edit.ts
var useCodeBlockEdit = (codeBlockService) => {
	const codeConfig = ref();
	const codeId = ref();
	const codeBlockEditorRef = useTemplateRef("codeBlockEditor");
	const createCodeBlock = async () => {
		codeConfig.value = {
			name: "",
			content: "({app, params, flowState}) => {\n  // place your code here\n}",
			params: []
		};
		codeId.value = await codeBlockService.getUniqueId();
		await nextTick();
		codeBlockEditorRef.value?.show();
	};
	const editCode = async (id) => {
		const codeBlock = await codeBlockService.getCodeContentById(id);
		if (!codeBlock) {
			tMagicMessage.error("获取代码块内容失败");
			return;
		}
		let codeContent = "";
		if (codeBlock.content) if (typeof codeBlock.content !== "string") codeContent = codeBlock.content.toString();
		else codeContent = codeBlock.content;
		codeConfig.value = {
			...cloneDeep(codeBlock),
			content: codeContent
		};
		codeId.value = id;
		await nextTick();
		codeBlockEditorRef.value?.show();
	};
	const deleteCode = async (key) => {
		codeBlockService.deleteCodeDslByIds([key]);
	};
	const submitCodeBlockHandler = async (values) => {
		if (!codeId.value) return;
		await codeBlockService.setCodeDslById(codeId.value, values);
		codeBlockEditorRef.value?.hide();
	};
	return {
		codeId,
		codeConfig,
		codeBlockEditor: codeBlockEditorRef,
		createCodeBlock,
		editCode,
		deleteCode,
		submitCodeBlockHandler
	};
};
//#endregion
export { useCodeBlockEdit };
