import { updateStatus } from "../utils/tree.js";
import { traverseNode } from "@tmagic/utils";
import { ref } from "vue";
//#region packages/editor/src/hooks/use-filter.ts
var useFilter = (nodeData, nodeStatusMap, filterNodeMethod) => {
	const filterIsMatch = (value, data) => {
		const string = !Array.isArray(value) ? [value] : value;
		if (!string.length) return true;
		return string.some((v) => filterNodeMethod(v, data));
	};
	const filter = (text) => {
		if (!nodeData.value.length) return;
		nodeData.value.forEach((node) => {
			traverseNode(node, (node, parents) => {
				if (!nodeStatusMap.value) return;
				const visible = filterIsMatch(text, node);
				if (visible && parents.length) parents.forEach((parent) => {
					if (text || text.length) updateStatus(nodeStatusMap.value, parent.id, {
						visible,
						expand: true
					});
				});
				updateStatus(nodeStatusMap.value, node.id, { visible });
			});
		});
	};
	return {
		filterText: ref(""),
		filterTextChangeHandler(text) {
			filter(text);
		}
	};
};
//#endregion
export { useFilter };
